func BaseWithContextAndSidebar(ctx goContext.Context, pageTitle string, sidebarComponent templ.Component, content templ.Component) templ.Component {
	// Get user email from context
	userEmail, err := appcontext.GetUserEmail(ctx)
	if err != nil {
		// Use default email if not available
		userEmail = "user@example.com"
	}

	// Retornar o componente que já inclui o email
	return BaseWithContentAndEmailAndSidebar(pageTitle, userEmail, sidebarComponent, content)
}

